import { useParams } from 'react-router-dom';
import './ProductDetails.css';

const mockProducts = {
  1: { name: 'Air Freshener', price: 1000, description: 'Freshens your room.', image: 'IMG-20250517-WA0020[1].jpg' },
  2: { name: 'Milo', price: 1500, description: 'Chocolate energy drink.', image: 'WhatsApp Image 2025-05-17 at 22.21.54_24346a45.jpg' },
  3: { name: 'Four Cousins', price: 4000, description: 'Red wine', image: 'WhatsApp Image 2025-05-17 at 22.21.56_efe7add8.jpg' },
  // Add other products here
};

function ProductDetails() {
  const { id } = useParams();
  const product = mockProducts[id];

  if (!product) return <div style={{ padding: 20 }}>Product not found.</div>;

  return (
    <div className="product-detail-container">
      <img
        src={`src/components/pages/utils/images/${product.image}`}
        alt={product.name}
        className="product-detail-image"
      />
      <div className="product-detail-info">
        <h2>{product.name}</h2>
        <p>{product.description}</p>
        <p><strong>₦{product.price}</strong></p>
        <button>Add to Cart</button>
      </div>
    </div>
  );
}

export default ProductDetails;
